 diff --git a/internal/csv/csv_test.go b/internal/csv/csv_test.go
new file mode 100644
--- /dev/null
+++ b/internal/csv/csv_test.go
@@
+package csv_test
+
+import (
+	"testing"
+
+	"github.com/dleblanc/kindling/internal/csv"
+)
+
+func TestWriteSingleRowNoTrailingNewline(t *testing.T) {
+	got := string(csv.Write([][]string{{"a", "b"}}))
+	if got != "a,b" {
+		t.Fatalf("got %q want %q", got, "a,b")
+	}
+}
+
+func TestWriteMultiRowNoTrailingNewline(t *testing.T) {
+	got := string(csv.Write([][]string{{"a", "b"}, {"1", "2"}}))
+	if got != "a,b\n1,2" {
+		t.Fatalf("got %q want %q", got, "a,b\n1,2")
+	}
+}
+
+func TestWriteHeaderPlusRows(t *testing.T) {
+	got := string(csv.Write([][]string{{"h1", "h2"}, {"a", "b"}, {"c", "d"}}))
+	if got != "h1,h2\na,b\nc,d" {
+		t.Fatalf("got %q want %q", got, "h1,h2\na,b\nc,d")
+	}
+}
+
+func TestWriteEmptyInput(t *testing.T) {
+	got := string(csv.Write(nil))
+	if got != "" {
+		t.Fatalf("got %q want empty", got)
+	}
+}

