+)
+
+func TestWriteSingleRowNoTrailingNewline(t *testing.T) {
+	got := string(csv.Write([][]string{{"a", "b"}}))
+	if want := "a,b"; got != want {
+		t.Fatalf("got %q want %q", got, want)
+	}
+}
+
+func TestWriteMultiRowNoTrailingNewline(t *testing.T) {
+	got := string(csv.Write([][]string{{"a", "b"}, {"1", "2"}}))
+	if want := "a,b\n1,2"; got != want {
+		t.Fatalf("got %q want %q", got, want)
+	}
+}
+
+func TestWriteHeaderPlusRows(t *testing.T) {
+	got := string(csv.Write([][]string{{"name", "age"}, {"alice", "30"}, {"bob", "40"}}))
+	if want := "name,age\nalice,30\nbob,40"; got != want {
+		t.Fatalf("got %q want %q", got, want)
+	}
+}
+
+func TestWriteEmptyNoOutput(t *testing.T) {
